import{_ as a,o,c as e,a2 as d}from"./chunks/framework.DnrXFDHb.js";const w=JSON.parse('{"title":"Ustawienia strony","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Page/page-settings.md","filePath":"pl-PL/Page/page-settings.md","lastUpdated":1781962217000}'),r={name:"pl-PL/Page/page-settings.md"};function n(i,t,l,s,y,u){return o(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="ustawienia-strony" tabindex="-1">Ustawienia strony <a class="header-anchor" href="#ustawienia-strony" aria-label="Permalink to &quot;Ustawienia strony&quot;">​</a></h1><p>Ustawienia strony kontrolują wygląd witryny, domyślne ustawienia strony uploadu, obrazy tła i wygląd panelu administracyjnego.</p><h2 id="ustawienia-globalne" tabindex="-1">Ustawienia globalne <a class="header-anchor" href="#ustawienia-globalne" aria-label="Permalink to &quot;Ustawienia globalne&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opcja</th><th>Cel</th></tr></thead><tbody><tr><td>Tytuł strony</td><td>Tytuł widoczny na karcie przeglądarki.</td></tr><tr><td>Ikona strony</td><td>Mała ikona widoczna na karcie przeglądarki.</td></tr><tr><td>Nazwa ImgBed</td><td>Nazwa widoczna na stronach frontendu.</td></tr><tr><td>Logo ImgBed</td><td>Obraz logo widoczny na stronach frontendu.</td></tr><tr><td>Link logo</td><td>URL otwierany po kliknięciu logo lub avatara.</td></tr><tr><td>Interwał zmiany tła</td><td>Czas rotacji wielu teł w milisekundach. <code>60000</code> oznacza 60 sekund.</td></tr><tr><td>Przezroczystość tła</td><td>Przezroczystość obrazu tła od <code>0</code> do <code>1</code>. Niższe wartości są jaśniejsze.</td></tr><tr><td>Domyślny prefiks URL</td><td>Prefiks używany przy generowaniu linków obrazów. Puste pole oznacza bieżącą domenę strony.</td></tr></tbody></table><h2 id="ustawienia-klienta" tabindex="-1">Ustawienia klienta <a class="header-anchor" href="#ustawienia-klienta" aria-label="Permalink to &quot;Ustawienia klienta&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opcja</th><th>Cel</th></tr></thead><tbody><tr><td>Ogłoszenie</td><td>Komunikat widoczny u góry strony uploadu. HTML jest obsługiwany.</td></tr><tr><td>Domyślny kanał uploadu</td><td>Kanał domyślnie wybrany na stronie uploadu. Możesz też wybrać Smart Dispatch.</td></tr><tr><td>Domyślny katalog uploadu</td><td>Domyślny katalog, np. <code>/user/</code>. Puste lub <code>/</code> oznacza katalog główny.</td></tr><tr><td>Domyślna metoda nazewnictwa</td><td>Strategia generowania nazwy pliku po uploadzie. Patrz niżej.</td></tr><tr><td>Domyślna konwersja do WebP</td><td>Konwertuje obrazy do WebP przed uploadem.</td></tr><tr><td>Domyślna kompresja</td><td>Kompresuje obrazy lokalnie w przeglądarce przed uploadem.</td></tr><tr><td>Domyślny próg kompresji</td><td>Automatycznie kompresuje obraz, gdy przekroczy ten rozmiar w MB.</td></tr><tr><td>Domyślny rozmiar docelowy</td><td>Docelowy rozmiar pliku po kompresji, w MB.</td></tr><tr><td>Tło strony logowania</td><td>Obraz tła dla strony logowania użytkownika.</td></tr><tr><td>Tło strony uploadu</td><td>Obraz tła dla strony uploadu.</td></tr><tr><td>Link portalu w stopce</td><td>URL otwierany przez przycisk portalu w stopce.</td></tr><tr><td>Ukryj stopkę</td><td>Ukrywa stopkę frontendu po włączeniu.</td></tr></tbody></table><h2 id="ustawienia-administratora" tabindex="-1">Ustawienia administratora <a class="header-anchor" href="#ustawienia-administratora" aria-label="Permalink to &quot;Ustawienia administratora&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opcja</th><th>Cel</th></tr></thead><tbody><tr><td>Tło logowania administratora</td><td>Obraz tła dla strony logowania administratora.</td></tr><tr><td>Tło administratora</td><td>Obraz tła dla stron administracyjnych. Można użyć jednego URL-a obrazu albo wielu URL-i.</td></tr><tr><td>Tryb ładowania obrazów</td><td>Tryb podglądu na liście plików administratora. Original ładuje oryginalne obrazy. Smart loading preferuje miniatury dla publicznych obrazów i oryginały dla ograniczonych obrazów.</td></tr><tr><td>Źródło miniatur</td><td>Usługa generowania miniatur: wsrv.nl, Cloudflare Image Resizing albo WordPress Photon. Cloudflare Image Resizing musi być włączone w Cloudflare przed wyborem.</td></tr><tr><td>Widget Live2D</td><td>Pokazuje postać Live2D w panelu administracyjnym.</td></tr><tr><td>Efekt fajerwerków po kliknięciu</td><td>Pokazuje efekt fajerwerków po kliknięciu strony.</td></tr><tr><td>Gwiezdny ślad kursora</td><td>Pokazuje ślad gwiazd podczas poruszania myszą.</td></tr></tbody></table><h2 id="formaty-obrazow-tła" tabindex="-1">Formaty obrazów tła <a class="header-anchor" href="#formaty-obrazow-tła" aria-label="Permalink to &quot;Formaty obrazów tła&quot;">​</a></h2><p>Tło strony logowania, tło strony uploadu i tło logowania administratora obsługują:</p><table tabindex="0"><thead><tr><th>Wartość</th><th>Efekt</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Używa rotacji tapet Bing.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Rotuje wiele obrazów.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Używa jednego obrazu tła.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Używa linku Random Image API. Możesz skonfigurować własne Random Image API w Innych ustawieniach, a potem wkleić tu wygenerowany link jako pojedyncze tło.</td></tr></tbody></table><p>Tło administratora obsługuje URL-e obrazów. Wiele URL-i można oddzielić angielskimi przecinkami, zgodnie z podpowiedzią na stronie. Puste pole oznacza użycie domyślnego tła.</p><h2 id="domyslna-metoda-nazewnictwa" tabindex="-1">Domyślna metoda nazewnictwa <a class="header-anchor" href="#domyslna-metoda-nazewnictwa" aria-label="Permalink to &quot;Domyślna metoda nazewnictwa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metoda</th><th>Wynik</th></tr></thead><tbody><tr><td>Default</td><td>Prefiks czasowo-losowy + oryginalna nazwa pliku, np. <code>1760000000000_cat.png</code>.</td></tr><tr><td>Tylko prefiks</td><td>Prefiks czasowo-losowy i rozszerzenie, np. <code>1760000000000.png</code>.</td></tr><tr><td>Tylko oryginalna nazwa</td><td>Zachowuje oryginalną nazwę pliku, np. <code>cat.png</code>. Przy duplikatach ImgBed dodaje <code>(1)</code>, <code>(2)</code> itd.</td></tr><tr><td>Krótki link</td><td>Używa 8-znakowego krótkiego ID i rozszerzenia, np. <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const p=a(r,[["render",n]]);export{w as __pageData,p as default};
